import{_ as t,o as i,c as a,a0 as n}from"./chunks/framework.Dx25mwie.js";const g=JSON.parse('{"title":"FAQ - Frequently Asked Questions","description":"","frontmatter":{},"headers":[],"relativePath":"en/docs/5.faq.md","filePath":"en/docs/5.faq.md"}'),o={name:"en/docs/5.faq.md"};function s(r,e,d,l,h,p){return i(),a("div",null,[...e[0]||(e[0]=[n(`<h1 id="faq-frequently-asked-questions" tabindex="-1">FAQ - Frequently Asked Questions <a class="header-anchor" href="#faq-frequently-asked-questions" aria-label="Permalink to &quot;FAQ - Frequently Asked Questions&quot;">​</a></h1><p>This page collects global frequently asked questions about Go-Spring. If you are looking for questions about a specific module, see the corresponding module documentation:</p><ul><li><a href="/en/docs/2.guides/02-ioc-container#faq">IoC Container FAQ</a></li><li><a href="/en/docs/2.guides/01-configuration">Configuration System</a></li><li><a href="/en/docs/2.guides/05-http-server">HTTP Server</a></li><li><a href="/en/docs/2.guides/07-testing">Testing</a></li></ul><hr><h2 id="project-overview" tabindex="-1">Project Overview <a class="header-anchor" href="#project-overview" aria-label="Permalink to &quot;Project Overview&quot;">​</a></h2><h3 id="q-what-is-go-spring-what-is-its-design-philosophy" tabindex="-1">Q: What is Go-Spring? What is its design philosophy? <a class="header-anchor" href="#q-what-is-go-spring-what-is-its-design-philosophy" aria-label="Permalink to &quot;Q: What is Go-Spring? What is its design philosophy?&quot;">​</a></h3><p><strong>A</strong>: Go-Spring is a Go dependency injection framework that inherits ideas from Spring. Its core design philosophy is:</p><ul><li><strong>Keep Go&#39;s native style</strong>: do not forcibly imitate Java Spring; solve Go problems in the Go way</li><li><strong>Discover and solve problems early</strong>: all dependency resolution is completed at startup, and the container is not involved at runtime</li><li><strong>Explicit over implicit</strong>: all dependencies are clearly visible, with no magic, avoiding hard-to-debug surprises</li><li><strong>Conditional mutual exclusion over override</strong>: Beans with the same name cannot be implicitly overridden; conditional matching decides which one takes effect</li><li><strong>Simplicity is beauty</strong>: avoid overengineering and solve only real problems</li></ul><h3 id="q-how-is-go-spring-different-from-other-go-dependency-injection-frameworks-wire-dig-fx" tabindex="-1">Q: How is Go-Spring different from other Go dependency injection frameworks (Wire, dig, fx)? <a class="header-anchor" href="#q-how-is-go-spring-different-from-other-go-dependency-injection-frameworks-wire-dig-fx" aria-label="Permalink to &quot;Q: How is Go-Spring different from other Go dependency injection frameworks (Wire, dig, fx)?&quot;">​</a></h3><p><strong>A</strong>:</p><table tabindex="0"><thead><tr><th>Feature</th><th>Go-Spring</th><th>Wire</th><th>dig</th><th>fx</th></tr></thead><tbody><tr><td><strong>Dependency resolution timing</strong></td><td>Startup-time reflection</td><td>Compile-time code generation</td><td>Runtime reflection</td><td>Runtime reflection</td></tr><tr><td><strong>Singleton by default</strong></td><td>✓</td><td>-</td><td>✓</td><td>✓</td></tr><tr><td><strong>Conditional registration</strong></td><td>✓</td><td>-</td><td>✗</td><td>✗</td></tr><tr><td><strong>Configuration binding</strong></td><td>Built in</td><td>Not built in</td><td>Not built in</td><td>Not built in</td></tr><tr><td><strong>Circular dependency support</strong></td><td>Automatically handled by field injection</td><td>Not supported</td><td>✗</td><td>✗</td></tr><tr><td><strong>Batch registration Group</strong></td><td>✓</td><td>-</td><td>✗</td><td>✗</td></tr></tbody></table><p>Go-Spring chooses the <strong>startup-time reflection</strong> path, which brings several benefits:</p><ul><li>No extra code generation step is needed, making the development workflow simpler</li><li>Supports conditional registration and dynamically deciding which Beans take effect based on configuration</li><li>Automatically handles circular dependencies through field injection</li><li>Built-in configuration binding without requiring third-party libraries</li></ul><p>If you prefer compile-time code generation, Wire is a great choice. If you like Go-Spring&#39;s design philosophy, it will feel very natural to use.</p><h3 id="q-why-is-it-called-go-spring-and-what-is-its-relationship-with-java-spring" tabindex="-1">Q: Why is it called Go-Spring, and what is its relationship with Java Spring? <a class="header-anchor" href="#q-why-is-it-called-go-spring-and-what-is-its-relationship-with-java-spring" aria-label="Permalink to &quot;Q: Why is it called Go-Spring, and what is its relationship with Java Spring?&quot;">​</a></h3><p><strong>A</strong>: Go-Spring inherits Spring&#39;s core ideas of <strong>Inversion of Control</strong> and <strong>Dependency Injection</strong>, but it is not a Go reimplementation of Java Spring.</p><p>We insist on Go&#39;s native design philosophy and do not copy Java Spring concepts directly into Go. Many design decisions differ from Java Spring, such as:</p><ul><li>Go-Spring does not support dynamically retrieving Beans at runtime; it resolves everything once at startup</li><li>Go-Spring does not allow Bean overriding; it insists on conditional mutual exclusion</li><li>Go-Spring requires interfaces to be explicitly exported and does not infer them automatically</li></ul><p>So it inherits the ideas, but it is not a port. It is a redesign in the Go way.</p><h3 id="q-is-go-spring-stable-now-can-it-be-used-in-production" tabindex="-1">Q: Is Go-Spring stable now? Can it be used in production? <a class="header-anchor" href="#q-is-go-spring-stable-now-can-it-be-used-in-production" aria-label="Permalink to &quot;Q: Is Go-Spring stable now? Can it be used in production?&quot;">​</a></h3><p><strong>A</strong>: Go-Spring has gone through years of iteration. Its core features are stable and have already been used in production environments.</p><hr><h2 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting Started&quot;">​</a></h2><h3 id="q-how-do-i-create-a-go-spring-project-from-scratch" tabindex="-1">Q: How do I create a Go-Spring project from scratch? <a class="header-anchor" href="#q-how-do-i-create-a-go-spring-project-from-scratch" aria-label="Permalink to &quot;Q: How do I create a Go-Spring project from scratch?&quot;">​</a></h3><p><strong>A</strong>: We recommend starting from the <a href="https://github.com/go-spring/starter" target="_blank" rel="noreferrer">starter</a> template:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Clone the template</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/go-spring/starter.git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-project</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-project</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Fetch dependencies</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">go</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mod</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tidy</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Run</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">go</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> main.go</span></span></code></pre></div><p>The template is already configured with the most commonly used starters, so you can develop directly on top of it.</p><h3 id="q-what-project-directory-structure-is-recommended" tabindex="-1">Q: What project directory structure is recommended? <a class="header-anchor" href="#q-what-project-directory-structure-is-recommended" aria-label="Permalink to &quot;Q: What project directory structure is recommended?&quot;">​</a></h3><p><strong>A</strong>: Go-Spring does not enforce a project structure. We recommend following Go community conventions:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>my-project/</span></span>
<span class="line"><span>├── main.go           # Entry file</span></span>
<span class="line"><span>├── go.mod            # Dependency management</span></span>
<span class="line"><span>├── config/           # Configuration types</span></span>
<span class="line"><span>├── service/          # Business services</span></span>
<span class="line"><span>├── controller/       # HTTP controllers</span></span>
<span class="line"><span>├── repository/       # Data access layer</span></span>
<span class="line"><span>└── model/            # Data models</span></span></code></pre></div><p>Basic principle: <strong>layer by domain and keep dependencies clear</strong>.</p><h3 id="q-where-can-i-find-complete-example-projects" tabindex="-1">Q: Where can I find complete example projects? <a class="header-anchor" href="#q-where-can-i-find-complete-example-projects" aria-label="Permalink to &quot;Q: Where can I find complete example projects?&quot;">​</a></h3><p><strong>A</strong>: Example projects are collected in <a href="https://github.com/go-spring/examples" target="_blank" rel="noreferrer">go-spring/examples</a>, which you can use as references.</p><hr><h2 id="development" tabindex="-1">Development <a class="header-anchor" href="#development" aria-label="Permalink to &quot;Development&quot;">​</a></h2><h3 id="q-how-do-i-run-tests" tabindex="-1">Q: How do I run tests? <a class="header-anchor" href="#q-how-do-i-run-tests" aria-label="Permalink to &quot;Q: How do I run tests?&quot;">​</a></h3><p><strong>A</strong>: Exactly the same as native Go:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">go</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./...</span></span></code></pre></div><p>For detailed testing usage, see <a href="/en/docs/2.guides/07-testing">07-testing.md</a>.</p><h3 id="q-how-can-i-contribute" tabindex="-1">Q: How can I contribute? <a class="header-anchor" href="#q-how-can-i-contribute" aria-label="Permalink to &quot;Q: How can I contribute?&quot;">​</a></h3><p><strong>A</strong>: Contributions are welcome!</p><ul><li>Report issues: <a href="https://github.com/go-spring/go-spring/issues" target="_blank" rel="noreferrer">github.com/go-spring/go-spring/issues</a></li><li>Submit Pull Requests: fork the repository, make changes, and submit a PR</li><li>Before contributing, read <a href="/en/CODING_STYLE">CODING_STYLE.md</a> to understand the coding conventions</li></ul><h3 id="q-why-was-my-bean-not-registered" tabindex="-1">Q: Why was my Bean not registered? <a class="header-anchor" href="#q-why-was-my-bean-not-registered" aria-label="Permalink to &quot;Q: Why was my Bean not registered?&quot;">​</a></h3><p><strong>A</strong>: Common reasons:</p><ol><li>You forgot to call <code>gs.Provide</code> in <code>init()</code> to register it</li><li>Its conditions were not satisfied and it was pruned by conditional matching; check your condition configuration</li><li>The Bean is not depended on. Go-Spring creates Beans on demand, so Beans that are not depended on are not instantiated (though they are still registered)</li></ol><h3 id="q-why-does-startup-fail-with-conflict-bean-already-registered" tabindex="-1">Q: Why does startup fail with &quot;conflict: bean already registered&quot;? <a class="header-anchor" href="#q-why-does-startup-fail-with-conflict-bean-already-registered" aria-label="Permalink to &quot;Q: Why does startup fail with &quot;conflict: bean already registered&quot;?&quot;">​</a></h3><p><strong>A</strong>: This error means two Beans of the same type and same name were registered at the same time.</p><p>Solutions:</p><ol><li>If you really need two instances, give them different names with <code>.Name(&quot;xxx&quot;)</code></li><li>If only one should take effect under different conditions, add conditional matching such as <code>OnProfiles</code></li><li>If you want to override in tests, <code>ctx.Provide</code> in tests does not affect the global context, so it is safe to override there</li></ol><p>Go-Spring does not allow Beans of the same type and same name to coexist under the same condition. This is a design choice to avoid hard-to-debug problems caused by implicit overriding.</p><hr><h2 id="performance" tabindex="-1">Performance <a class="header-anchor" href="#performance" aria-label="Permalink to &quot;Performance&quot;">​</a></h2><h3 id="q-is-go-spring-slow-to-start-does-it-have-high-runtime-overhead" tabindex="-1">Q: Is Go-Spring slow to start? Does it have high runtime overhead? <a class="header-anchor" href="#q-is-go-spring-slow-to-start-does-it-have-high-runtime-overhead" aria-label="Permalink to &quot;Q: Is Go-Spring slow to start? Does it have high runtime overhead?&quot;">​</a></h3><p><strong>A</strong>:</p><ul><li><strong>Startup overhead</strong>: all dependency injection is completed at startup. Startup time is positively correlated with the number of Beans, and typical projects start within tens of milliseconds</li><li><strong>Runtime overhead</strong>: after startup, all metadata is cleaned up. There is no extra runtime overhead, and performance is the same as handwritten code</li><li><strong>Memory usage</strong>: only your Beans consume memory. The container itself uses almost no memory after startup</li></ul><p>So there is no need to worry about performance. Go-Spring is very lightweight at runtime.</p><h3 id="q-how-can-i-optimize-startup-speed" tabindex="-1">Q: How can I optimize startup speed? <a class="header-anchor" href="#q-how-can-i-optimize-startup-speed" aria-label="Permalink to &quot;Q: How can I optimize startup speed?&quot;">​</a></h3><p><strong>A</strong>:</p><ol><li>On-demand creation is enabled by default, so Beans that are not depended on are not created, saving time</li><li>Register only the Beans you actually need; avoid registering large amounts of unused code</li><li>Split modules and use conditional registration, enabling them only when needed</li></ol><hr><h2 id="about-this-documentation" tabindex="-1">About This Documentation <a class="header-anchor" href="#about-this-documentation" aria-label="Permalink to &quot;About This Documentation&quot;">​</a></h2><p>This documentation is continuously improving. If you have new questions, feel free to submit an Issue to add them.</p>`,62)])])}const u=t(o,[["render",s]]);export{g as __pageData,u as default};
